import React, { useState, useEffect } from 'react';
import api from '../api';

const AnalyticsDashboard = () => {
  const [analytics, setAnalytics] = useState(null);
  const [year, setYear] = useState(2024);
  const [month, setMonth] = useState(1);

  useEffect(() => {
    fetchAnalytics();
  }, [year, month]);

  const fetchAnalytics = async () => {
    try {
      const res = await api.get(`/analytics/monthly?year=${year}&month=${month}`);
      setAnalytics(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  if (!analytics) return <div className="text-center py-12 text-gray-500">Loading analytics...</div>;

  return (
    <div>
      <div className="flex space-x-2 mb-6">
        <input type="number" value={year} onChange={(e) => setYear(e.target.value)} className="w-24 p-2 border rounded" />
        <input type="number" min="1" max="12" value={month} onChange={(e) => setMonth(e.target.value)} className="w-24 p-2 border rounded" />
        <button onClick={fetchAnalytics} className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600">Update</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-gradient-to-r from-green-400 to-green-600 text-white p-8 rounded-2xl shadow-2xl text-center">
          <h3 className="text-xl font-semibold opacity-90 mb-2">Savings Rate</h3>
          <p className="text-4xl font-bold">{analytics.savingsRate}%</p>
        </div>
        <div className="bg-gradient-to-r from-blue-400 to-blue-600 text-white p-8 rounded-2xl shadow-2xl text-center">
          <h3 className="text-xl font-semibold opacity-90 mb-2">Expense Std Dev</h3>
          <p className="text-4xl font-bold">${analytics.expenseStd}</p>
        </div>
        <div className="bg-gradient-to-r from-orange-400 to-orange-600 text-white p-8 rounded-2xl shadow-2xl text-center">
          <h3 className="text-xl font-semibold opacity-90 mb-2">Budget Usage</h3>
          <p className="text-4xl font-bold">{analytics.budgetUsage}</p>
        </div>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;
